class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        from itertools import product

        def is_palindrome(x):
            return str(x) == str(x)[::-1]

        def generate_palindromes(limit):
            palindromes = set()
            length = len(str(limit))

            # Generate palindromes with length <= length
            for l in range(1, length + 1):
                # Generate first half of the palindrome
                for first_half in range(10 ** ((l + 1) // 2)):
                    first_half_str = str(first_half)
                    if l % 2 == 0:
                        full_str = first_half_str + first_half_str[::-1]
                    else:
                        full_str = first_half_str + first_half_str[-2::-1]
                    palindrome = int(full_str)
                    if palindrome < limit:
                        palindromes.add(palindrome)
            return palindromes

        # Generate all palindromic numbers less than 10^9
        palindromes = generate_palindromes(10**9)

        # Find the median of nums to minimize total cost
        median = sorted(nums)[len(nums) // 2]

        # Find the closest palindrome to the median
        closest_pal = None
        min_diff = float('inf')
        for p in palindromes:
            diff = abs(p - median)
            if diff < min_diff:
                min_diff = diff
                closest_pal = p

        # Compute total cost to convert all elements to closest_pal
        total_cost = sum(abs(num - closest_pal) for num in nums)

        return total_cost
